INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 103411, 1034501039, "", "", 1034501, 870, 13, "", "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 103411, 1034501040, "", 0, 1034501, "わあ……素敵なケーキね！\nえ？　キミが作ったの？\nすごいじゃない！", 11, 1, 0, 4);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1034501041, "", "", 1034501, "", 91, "", "", "");
