INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 104611, 1046501043, "", 0, 1046501, "たい焼きの他にケーキまで\n作れるにゃんて……\nキミって意外と料理上手にゃ？", 11, 1, 0, 6);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1046501044, "", "", 1046501, "", 91, "", "", "");
