INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "vo_adv_1052501", 1052501038, "", "", 1052501, "vo_adv_1052501_000", 21, "", "", 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 105211, 1052501039, "", "", 1052501, 870, 13, "", "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 105211, 1052501040, "", 0, 1052501, "素敵なケーキをありがとう！\nまさかこんな盛大に\nお祝いしてもらえるなんて\n思わなかったわ！", 11, 1, 0, 6);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1052501041, "", "", 1052501, "", 91, "", "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "vo_adv_1052501", 1052501042, "", "", 1052501, "vo_adv_1052501_001", 21, "", "", 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 105211, 1052501043, "", 0, 1052501, "おめでとうって言ってもらえるだけでも\nうれしいのに、手作りのケーキまで……\n私、あなたにいろんなものを\nもらってばっかりね。", 11, 1, 0, 6);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1052501044, "", "", 1052501, "", 91, "", "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "vo_adv_1052501", 1052501045, "", "", 1052501, "vo_adv_1052501_002", 21, "", "", 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 105211, 1052501046, "", 0, 1052501, "少しでもお返ししたいけど……\nあなたは何かしてほしいことはある？\nえ？　私の誕生日だから私が\n喜んでくれたらうれしい……？", 11, 1, 0, 5);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1052501047, "", "", 1052501, "", 91, "", "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "vo_adv_1052501", 1052501048, "", "", 1052501, "vo_adv_1052501_003", 21, "", "", 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 105211, 1052501049, "", 0, 1052501, "私、もう十分に喜んでるわ！\nでも、あなたのそんな言葉を聞いたら\nもう少しわがままを\n言いたくなっちゃうわ。", 11, 1, 0, 5);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1052501050, "", "", 1052501, "", 91, "", "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "vo_adv_1052501", 1052501051, "", "", 1052501, "vo_adv_1052501_004", 21, "", "", 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (1, 105211, 1052501052, "", 0, 1052501, "ケーキをあーんしてもらってもいい？\n一口だけ、一口だけでいいから！\nいいの？　ありがとう！\n最高の誕生日だわ！", 11, 1, 0, 4);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", 0, 1052501053, "", "", 1052501, "", 91, "", "", "");
